import { describe, expect, it } from 'vitest'

import { sort } from './index.js'

describe('Sort by', _ => {
  it('Standard array - numbers', async () => {
    const array = [3, 1, 2]
    const sorted = sort(array)
    const reversed = sort(array, { reverse: true })
    expect(sorted).toEqual([1, 2, 3])
    expect(reversed).toEqual([3, 2, 1])
  })

  it('Standard array - strings', async () => {
    const array = ['c', 'a', 'b']
    const sorted = sort(array)
    const reversed = sort(array, { reverse: true })
    expect(sorted).toEqual(['a', 'b', 'c'])
    expect(reversed).toEqual(['c', 'b', 'a'])
  })

  it('Standard array - dates', async () => {
    const array = [
      new Date('2021-05-18'),
      new Date('2022-01-01'),
      new Date('2025-03-09'),
    ]
    const sorted = sort(array)
    const reversed = sort(array, { reverse: true })
    expect(sorted).toEqual([
      new Date('2021-05-18'),
      new Date('2022-01-01'),
      new Date('2025-03-09'),
    ])
    expect(reversed).toEqual([
      new Date('2025-03-09'),
      new Date('2022-01-01'),
      new Date('2021-05-18'),
    ])
  })
  it('Array of objects — simple integer', async () => {
    const array = [
      { name: 'Ace', age: 30 },
      { name: 'Betty', age: 25 },
      { name: 'Candy', age: 35 },
    ]
    const sorted = sort(array, { props: 'age' })
    const reversed = sort(array, { props: 'age', reverse: true })
    expect(sorted).toEqual([
      { name: 'Betty', age: 25 },
      { name: 'Ace', age: 30 },
      { name: 'Candy', age: 35 },
    ])
    expect(reversed).toEqual([
      { name: 'Candy', age: 35 },
      { name: 'Ace', age: 30 },
      { name: 'Betty', age: 25 },
    ])
  })

  it('Array of objects — simple string', async () => {
    const array = [
      { name: 'Ace', age: 30 },
      { name: 'Betty', age: 25 },
      { name: 'Candy', age: 35 },
    ]
    const sorted = sort(array, { props: 'name' })
    const reversed = sort(array, { props: 'name', reverse: true })
    expect(sorted).toEqual([
      { name: 'Ace', age: 30 },
      { name: 'Betty', age: 25 },
      { name: 'Candy', age: 35 },
    ])
    expect(reversed).toEqual([
      { name: 'Candy', age: 35 },
      { name: 'Betty', age: 25 },
      { name: 'Ace', age: 30 },
    ])
  })

  it('Double property', async () => {
    const array = [
      { name: 'Ace', age: 30 },
      { name: 'Betty', age: 25 },
      { name: 'Candy', age: 35 },
      { name: 'Danny', age: 30 },
    ]
    const sorted = sort(array, { props: ['age', 'name'] })
    const reversed = sort(array, { props: ['age', 'name'], reverse: true })
    expect(sorted).toEqual([
      { name: 'Betty', age: 25 },
      { name: 'Ace', age: 30 },
      { name: 'Danny', age: 30 },
      { name: 'Candy', age: 35 },
    ])
    expect(reversed).toEqual([
      { name: 'Candy', age: 35 },
      { name: 'Danny', age: 30 },
      { name: 'Ace', age: 30 },
      { name: 'Betty', age: 25 },
    ])
  })

  it('Nested value', async () => {
    const array = [
      { data: { value: 1 } },
      { data: { value: 2 } },
      { data: { value: 3 } },
    ]
    const sorted = sort(array, { props: 'data.value' })
    const reversed = sort(array, { props: 'data.value', reverse: true })
    expect(sorted).toEqual([
      { data: { value: 1 } },
      { data: { value: 2 } },
      { data: { value: 3 } },
    ])
    expect(reversed).toEqual([
      { data: { value: 3 } },
      { data: { value: 2 } },
      { data: { value: 1 } },
    ])
  })
})
